def total_sales(a: int, b: int, c: int, d: int) -> int {
    total: int = 0;
    total += a;
    total += b;
    total += c;
    total += d;
    return total;
}

def average_sales(a: int, b: int, c: int, d: int) -> int {
    total: int = total_sales(a, b, c, d);
    average: int = total / 4;
    return average;
}

